#include <stdio.h>
#include <stdlib.h>
#define MAXN 100005
int n;
int tree[MAXN][2];
int graph[MAXN][2];
int visited[MAXN];
int count;
void dfs(int node) {
    visited[node] = 1;
    count++;
    if (tree[node][0] != -1 && !visited[tree[node][0]]) {
        dfs(tree[node][0]);
    }
    if (tree[node][1] != -1 && !visited[tree[node][1]]) {
        dfs(tree[node][1]);
    }
}
int main() {
    scanf("%d", &n);
    for (int i = 0; i < n - 1; i++) {
        int u, v;
        scanf("%d %d", &u, &v);
        if (tree[u][0] == -1) {
            tree[u][0] = v;
        } else {
            tree[u][1] = v;
        }
        if (tree[v][0] == -1) {
            tree[v][0] = u;
        } else {
            tree[v][1] = u;
        }
    }
    for (int i = 1; i <= n; i++) {
        int u, v;
        scanf("%d %d", &u, &v);
        graph[u][0] = v;
    }
    for (int i = 1; i <= n; i++) {
        count = 0;
        for (int j = 1; j <= n; j++) {
            visited[j] = 0;
        }
        dfs(1);
        int components = 0;
        for (int j = 1; j <= n; j++) {
            if (!visited[j]) {
                components++;
                dfs(j);
            }
        }
        printf("%d\n", components);
    }
    return 0;
}

