import java.util.ArrayList;
import java.util.Scanner;
public class Main {
    static final int MAXN = 100005;
    static int n;
    static ArrayList<Integer>[] tree = new ArrayList[MAXN];
    static ArrayList<Integer>[] graph = new ArrayList[MAXN];
    static boolean[] visited = new boolean[MAXN];
    static int count;
    public static void dfs(int node) {
        visited[node] = true;
        count++;
        for (int i = 0; i < tree[node].size(); i++) {
            if (!visited[tree[node].get(i)]) {
                dfs(tree[node].get(i));
            }
        }
    }
    public static void main(String[] args) {
        Scanner sc = new Scanner(System.in);
        n = sc.nextInt();
        for (int i = 0; i < MAXN; i++) {
            tree[i] = new ArrayList<>();
            graph[i] = new ArrayList<>();
        }
        for (int i = 0; i < n - 1; i++) {
            int u = sc.nextInt();
            int v = sc.nextInt();
            tree[u].add(v);
            tree[v].add(u);
        }
        for (int i = 1; i <= n; i++) {
            int u = sc.nextInt();
            int v = sc.nextInt();
            graph[u].add(v);
        }
        for (int i = 1; i <= n; i++) {
            count = 0;
            for (int j = 1; j <= n; j++) {
                visited[j] = false;
            }
            dfs(1);
            int components = 0;
            for (int j = 1; j <= n; j++) {
                if (!visited[j]) {
                    components++;
                    dfs(j);
                }
            }
            System.out.println(components);
        }
    }
}

